      // Orlando test intersection (S Parramore Ave @ W South St)
      // urlQueryString = `?username=GeotabEcoDrive&password=ypT8zDBk`
      //   + `&includeTopology=yes&includeLanes=yes&asTurns=yes&returnJSON=yes`
      //   + `&latitude=28.538311&longitude=-81.388466`
      //   + `&heading=270&bearingType=Compass`
      //   + `&version=1.0.12`;    
      // Orlando test intersection (E Robinson St @ N Rosalind Ave)
