      //   + `&includeTopology=yes&includeLanes=yes&asTurns=yes&returnJSON=yes`
      //   + `&latitude=28.545707&longitude=-81.374790`
      //   + `&heading=270&bearingType=Compass`
      //   + `&version=1.0.12`;  
      // Kitchener demo intersection (Glasgow St @ Belmont Ave)
      // urlQueryString = `?username=GeotabEcoDrive&password=ypT8zDBk`
      //   + `&includeTopology=yes&includeLanes=yes&asTurns=yes&returnJSON=yes`
      //   + `&latitude=43.451594&longitude=-80.517831`
      //   + `&heading=60&bearingType=Compass`
